examples.code:
public class Product {
    String name;
    double price;
    Product(String name, double price) {
        this.name = name; this.price = price;
    }
    @Override
    public String toString() {
        return "Product[name=%s, price=%.2f]".formatted(name, price);
    }
}
System.out.println(new Product("Widget", 9.99));

