public class Main {
    static class Student {
        String name;
        int grade;
        Student(String name, int grade) {
            this.name = name; this.grade = grade;
        }
        // Override toString() to return: "Student{name='Alice', grade=90}"
    }
    public static void main(String[] args) {
        Student s = new Student("Alice", 90);
        System.out.println(s); // Uses toString()
        System.out.println("Info: " + s); // Concatenation also uses toString()
    }
}
